const t=JSON.parse('{"key":"v-2416bc68","path":"/tech/java/spring/Spring%E4%BA%8B%E5%8A%A1%E5%88%86%E6%9E%90.html","title":"Spring事务分析","lang":"zh-CN","frontmatter":{"date":"2020-07-02T17:05:00.000Z","category":["Java"],"tag":["Spring"],"description":"Spring事务分析 Propagation REQUIRED：支持当前事务，如果当前没有事务，就新建一个事务。这是最常见的选择。 SUPPORTS：支持当前事务，如果当前没有事务，就以非事务方式执行。 MANDATORY：支持当前事务，如果当前没有事务，就抛出异常。 REQUIRES_NEW：新建事务，如果当前存在事务，把当前事务挂起。 NOT_SUPPORTED：以非事务方式执行操作，如果当前存在事务，就把当前事务挂起。 NEVER：以非事务方式执行，如果当前存在事务，则抛出异常。 NESTED：支持当前事务，如果当前事务存在，则执行一个嵌套事务，如果当前没有事务，就新建一个事务。","head":[["meta",{"property":"og:url","content":"https://dhbin.cn/tech/java/spring/Spring%E4%BA%8B%E5%8A%A1%E5%88%86%E6%9E%90.html"}],["meta",{"property":"og:site_name","content":"DHB"}],["meta",{"property":"og:title","content":"Spring事务分析"}],["meta",{"property":"og:description","content":"Spring事务分析 Propagation REQUIRED：支持当前事务，如果当前没有事务，就新建一个事务。这是最常见的选择。 SUPPORTS：支持当前事务，如果当前没有事务，就以非事务方式执行。 MANDATORY：支持当前事务，如果当前没有事务，就抛出异常。 REQUIRES_NEW：新建事务，如果当前存在事务，把当前事务挂起。 NOT_SUPPORTED：以非事务方式执行操作，如果当前存在事务，就把当前事务挂起。 NEVER：以非事务方式执行，如果当前存在事务，则抛出异常。 NESTED：支持当前事务，如果当前事务存在，则执行一个嵌套事务，如果当前没有事务，就新建一个事务。"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:locale","content":"zh-CN"}],["meta",{"property":"og:updated_time","content":"2023-03-22T17:33:14.000Z"}],["meta",{"property":"article:author","content":"DHB"}],["meta",{"property":"article:tag","content":"Spring"}],["meta",{"property":"article:published_time","content":"2020-07-02T17:05:00.000Z"}],["meta",{"property":"article:modified_time","content":"2023-03-22T17:33:14.000Z"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"Article\\",\\"headline\\":\\"Spring事务分析\\",\\"image\\":[\\"\\"],\\"datePublished\\":\\"2020-07-02T17:05:00.000Z\\",\\"dateModified\\":\\"2023-03-22T17:33:14.000Z\\",\\"author\\":[{\\"@type\\":\\"Person\\",\\"name\\":\\"DHB\\",\\"url\\":\\"https://dhbin.cn\\"}]}"]]},"headers":[{"level":2,"title":"Propagation","slug":"propagation","link":"#propagation","children":[]},{"level":2,"title":"TransactionSynchronizationManager","slug":"transactionsynchronizationmanager","link":"#transactionsynchronizationmanager","children":[]},{"level":2,"title":"事务失效情景","slug":"事务失效情景","link":"#事务失效情景","children":[{"level":3,"title":"Propagation配置失效","slug":"propagation配置失效","link":"#propagation配置失效","children":[]}]}],"git":{"createdTime":1679407002000,"updatedTime":1679506394000,"contributors":[{"name":"dhb","email":"xx158@qq.com","commits":2}]},"readingTime":{"minutes":1.28,"words":385},"filePathRelative":"tech/java/spring/Spring事务分析.md","localizedDate":"2020年7月2日","excerpt":"<h1> Spring事务分析</h1>\\n<h2> Propagation</h2>\\n<ul>\\n<li>REQUIRED：支持当前事务，如果当前没有事务，就新建一个事务。这是最常见的选择。</li>\\n<li>SUPPORTS：支持当前事务，如果当前没有事务，就以非事务方式执行。</li>\\n<li>MANDATORY：支持当前事务，如果当前没有事务，就抛出异常。</li>\\n<li>REQUIRES_NEW：新建事务，如果当前存在事务，把当前事务挂起。</li>\\n<li>NOT_SUPPORTED：以非事务方式执行操作，如果当前存在事务，就把当前事务挂起。</li>\\n<li>NEVER：以非事务方式执行，如果当前存在事务，则抛出异常。</li>\\n<li>NESTED：支持当前事务，如果当前事务存在，则执行一个嵌套事务，如果当前没有事务，就新建一个事务。</li>\\n</ul>","autoDesc":true}');export{t as data};
